// Kontrollera om lead redan finns (Supabase returnerar array)
// Om arrayen är tom = ny lead, gå vidare
// Om arrayen innehåller element = dubblett, stoppa
const existing = $input.item.json;
const count = Array.isArray(existing) ? existing.length : 0;

if (count > 0) {
  // Lead finns redan — returnera tomt för att stoppa flödet
  return [];
}

// Ny lead — skicka vidare webhook-data
return [{ json: $('Webhook: Inkommande lead').item.json }];

