parameters.jsCode:
// Parsar Claude AI:s JSON-svar säkert
try {
  const text = $input.item.json.text;
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('Inget JSON hittades i AI-svaret');

  const scoring = JSON.parse(jsonMatch[0]);

  return {
    json: {
      ...scoring,
      lead_data: $('Webhook: Inkommande lead').item.json,
      scored_at: new Date().toISOString()
    }
  };
} catch (error) {
  throw new Error(`Fel vid JSON-parsning av AI-svar: ${error.message}`);
}

